class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> result;
        dfs(num, 0, result);
        return result;
    }

    bool dfs(string& num, int start, vector<int>& result) {
        if (start == num.size() && result.size() >= 3) {
            return true;
        }
        for (int i = start; i < num.size(); i++) {
            if (num[start] == '0' && i > start) {
                break;
            }
            long long cur = stoll(num.substr(start, i - start + 1));
            if (cur > INT_MAX) {
                break;
            }
            int size = result.size();
            if (size >= 2 && cur > result[size - 1] + result[size - 2]) {
                break;
            }
            if (size <= 1 || cur == (result[size - 1] + result[size - 2])) {
                result.push_back(cur);
                if (dfs(num, i + 1, result)) {
                    return true;
                }
                result.pop_back();
            }
        }
        return false;
    }
};

